kpi_card_patterns.card_rag_background:
// Conditional formatting on a card based on metric value:
// Use a measure to return the card background color
Sev5 Card Color =
VAR _Val = [Sev5 Count Current]
RETURN
    IF(ISBLANK(_Val), "#FFFFFF",
    IF(_Val >= 100, "#FF4444",  -- Red
    IF(_Val >= 50,  "#FFC000",  -- Amber
    "#70AD47")))                -- Green
// In Format pane > Background > Conditional formatting > Field value > [Sev5 Card Color]

