dashboard_title_and_context.last_refresh_card:
// Show when data was last refreshed
Last Refresh =
    FORMAT(NOW(), "DD MMM YYYY HH:MM")
// In a card visual at the bottom of the report page

dashboard_title_and_context.data_as_of_measure:
// For snapshot data: show the latest period in the model
Data As Of =
    FORMAT(MAX('DateTable'[Date]), "MMMM YYYY")
// Useful when the slicer shows 'All' — confirms the latest data period
